// Script Continued Below


// NOTE: Run this with test set to true to see the items that will change
//       Run this with test set to false (how it should ship) to update all of the OU Hierarchy Administration fields.
var test = false;
// NOTE: set below to true to rerun, by default we provide it with the value true so the fix script can be run more than once
var clearAndRerun = true; 

// clear and rerun
if(clearAndRerun && !test){
	clearOUHierarchyAdministrators();
}

count_OU_Hiearchy_Administrators();
update_OU_Hiearchy_Administrators();

function update_OU_Hiearchy_Administrators(){



	var OU_Members = new GlideRecord('x_153465_discovert_discover_office_members');
	OU_Members.addQuery('is_office_administrator',true);
	OU_Members.orderBy('discover_office_hierarchy');
	OU_Members.query();
	var currentCount = 0;
	var previousOU = '';
	var currentOU = '';
	var previousOUdiplayValue = '';
	var currentOUdiplayValue = '';
	var a_ou_hierarchy_administrators_value = [];
	var a_ou_hierarchy_administrators_displayValue = [];

	while(OU_Members.next()){
		currentOUdiplayValue = OU_Members.getDisplayValue('discover_office_hierarchy');
		currentOU = OU_Members.getValue('discover_office_hierarchy');
		if(currentOUdiplayValue != previousOUdiplayValue){
			// write when changes and at the end
			if(previousOUdiplayValue != ''){
				update_ou_hierarchy_administrators(previousOU, previousOUdiplayValue, currentCount, a_ou_hierarchy_administrators_value.join(','), a_ou_hierarchy_administrators_displayValue.join(','));
			}
			// reset previous after output
			previousOU = currentOU;
			previousOUdiplayValue = currentOUdiplayValue;
			a_ou_hierarchy_administrators_value = [];
			a_ou_hierarchy_administrators_displayValue = [];
			currentCount = 0;
		}

		currentCount++;
		a_ou_hierarchy_administrators_value.push(OU_Members.getValue('office_member'));
		a_ou_hierarchy_administrators_displayValue.push(OU_Members.getDisplayValue('office_member'));
	}
	// add the last OU, after the completion of the while loop
	if(currentCount>0){
		update_ou_hierarchy_administrators(currentOU, currentOUdiplayValue, currentCount, a_ou_hierarchy_administrators_value.join(','), a_ou_hierarchy_administrators_displayValue.join(','));
	}

//https://ven02975.service-now.com/x_153465_discovert_discover_office_members_list.do?sysparm_query=is_office_administrator%3Dtrue&sysparm_view=
}

function clearOUHierarchyAdministrators(){
	var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy'); 
	grOU.query(); 
    while (grOU.next()) { 
		grOU.u_ou_hierarchy_administrators = '';
		grOU.setWorkflow(false); // do not trigger business rules/workflows
		grOU.autoSysFields(false); // do not update system fields
		grOU.update('Fix Script - Tasker 2.7- OU Hierarchy Adinistration Update - roll back setting for OU Hierarchy Administrators to rerun');
       } 
}

function update_ou_hierarchy_administrators(ou, ou_displayValue, count, ou_hierarchy_administrators_value, ou_hierarchy_administrators_displayValue){

	var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
	if(grOU.get(ou)){
		// if test set, don't update
		if(!test){
			grOU.u_ou_hierarchy_administrators = ou_hierarchy_administrators_value;
			grOU.update('Fix Script - Tasker 2.7- OU Hierarchy Adinistration Update - set OU Hierarchy Administrators');
		}
		writeOUCount(ou_displayValue, count, ou_hierarchy_administrators_displayValue);	
	} else {
		gs.error('Fix Script - Tasker 2.7- OU Hierarchy Adinistration Update: Error - could not find OU (' + ou_displayValue + ') to update the OU Hiearchy Administrators field.  OU Guid:(' + ou + ')');
	}

}

function writeOUCount(ou, count, ou_hierarchy_administrators_displayValue){
	gs.info('Fix Script - Tasker 2.7- OU Hierarchy Adinistration Update - found (' + count + ') members in OU (' + ou + ') with OU Hiearchy Administration permissions.  OU(' + ou + ') - OU Hiearchy Administrators on the OU was set to (' + ou_hierarchy_administrators_displayValue + ')');
}

function count_OU_Hiearchy_Administrators(){
	// count all members who are Hiearchy Administrators
	var memberHACount = 0;
	var ga = new GlideAggregate('x_153465_discovert_discover_office_members');
	ga.addEncodedQuery('^is_office_administrator=true');
	ga.addAggregate("COUNT");
	ga.query();
	if(ga.next()){
		memberHACount = ga.getAggregate("COUNT");
	}

	gs.info('Fix Script - Tasker 2.7- OU Hierarchy Adinistration Update - Your system was analyzed and ' + memberHACount + ' should be added to the OU Hierarchy Administrator fields on the OU');
}
